        }
        .app { max-width: 1400px; margin: 0 auto; padding: 20px; }

        /* 顶部 */
        .header {
            text-align: center;
            padding: 30px 20px 20px;
            background: linear-gradient(135deg, #1e293b, #334155);
            border-radius: 16px;
            margin-bottom: 20px;
            border: 1px solid #475569;
        }
        .header h1 { font-size: 2em; color: #38bdf8; margin-bottom: 6px; }
        .header p { color: #94a3b8; font-size: 0.95em; }

        /* 搜索栏 */
        .search-area {
            display: flex; gap: 12px; margin: 20px 0;
            flex-wrap: wrap; align-items: center;
        }
        #searchInput {
            flex: 1; min-width: 250px;
            padding: 14px 20px;
            background: #1e293b;
            border: 2px solid #475569;
            border-radius: 12px;
            color: #f1f5f9;
            font-size: 1.05em;
            transition: border-color .3s;
        }
        #searchInput:focus { outline: none; border-color: #38bdf8; }
        #searchInput::placeholder { color: #64748b; }

        /* 筛选按钮 */
        .filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
        .fbtn {
            padding: 8px 18px;
            background: #1e293b;
            color: #94a3b8;
            border: 1px solid #475569;
            border-radius: 20px;
            cursor: pointer;
            font-size: 0.9em;
            transition: all .2s;
        }
        .fbtn:hover { border-color: #38bdf8; color: #38bdf8; }
        .fbtn.active { background: #38bdf8; color: #0f172a; border-color: #38bdf8; font-weight: 600; }
        .fbtn.warn-btn.active { background: #ef4444; border-color: #ef4444; color: #fff; }

        /* 统计栏 */
        .stats {
            display: flex; gap: 12px; margin-bottom: 20px; flex-wrap: wrap;
        }
        .stat-card {
            flex: 1; min-width: 140px;
            background: #1e293b;
            border: 1px solid #475569;
            border-radius: 12px;
            padding: 16px;
            text-align: center;
        }
        .stat-card .num { font-size: 2em; font-weight: 700; color: #38bdf8; }
        .stat-card .label { font-size: 0.85em; color: #94a3b8; margin-top: 4px; }
        .stat-card.warn .num { color: #ef4444; }

        /* 期限长度筛选 */
        .duration-filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
        .dbtn {
            padding: 6px 14px;
            background: transparent;
            color: #94a3b8;
            border: 1px dashed #475569;
            border-radius: 16px;
            cursor: pointer;
            font-size: 0.85em;
            transition: all .2s;
        }
        .dbtn:hover { border-color: #a78bfa; color: #a78bfa; }
        .dbtn.active { background: #a78bfa; color: #0f172a; border-style: solid; border-color: #a78bfa; font-weight: 600; }

        /* 卡片列表 */
        .cards { display: grid; grid-template-columns: repeat(auto-fill, minmax(420px, 1fr)); gap: 16px; }
        .card {
            background: #1e293b;
            border: 1px solid #334155;
            border-radius: 14px;
            padding: 20px;
            transition: all .3s;
            cursor: pointer;
            position: relative;
            overflow: hidden;
        }
        .card:hover { border-color: #38bdf8; transform: translateY(-2px); box-shadow: 0 8px 25px rgba(56,189,248,.1); }
        .card.warn-card { border-left: 4px solid #ef4444; }
        .card .cat-tag {
            display: inline-block;
            padding: 3px 10px;
            border-radius: 10px;
            font-size: 0.75em;
            font-weight: 600;
            margin-bottom: 10px;
        }
        .cat-labor .cat-tag { background: #164e63; color: #22d3ee; }
        .cat-commercial .cat-tag { background: #1e3a5f; color: #60a5fa; }
        .cat-economic .cat-tag { background: #365314; color: #a3e635; }
        .cat-civil .cat-tag { background: #4a1d96; color: #c4b5fd; }
        .cat-procedure .cat-tag { background: #78350f; color: #fbbf24; }
        .cat-criminal .cat-tag { background: #4a0e0e; color: #fca5a5; }
        .cat-admin .cat-tag { background: #134e4a; color: #5eead4; }

        .card .title { font-size: 1.15em; font-weight: 700; color: #f1f5f9; margin-bottom: 8px; }
        .card .duration {
            display: inline-block;
            padding: 4px 12px;
            background: rgba(56,189,248,.15);
            color: #38bdf8;
            border-radius: 8px;
            font-weight: 700;
            font-size: 1.05em;
            margin-bottom: 10px;
        }
        .card.warn-card .duration { background: rgba(239,68,68,.15); color: #ef4444; }
        .card .warn-badge {
            position: absolute; top: 12px; right: 12px;
            background: #ef4444; color: #fff;
            padding: 2px 8px; border-radius: 6px;
            font-size: 0.7em; font-weight: 700;
        }
        .card .desc { color: #94a3b8; font-size: 0.9em; line-height: 1.7; margin-bottom: 8px; }
        .card .law-ref {
            font-size: 0.8em; color: #64748b;
            border-top: 1px solid #334155;
            padding-top: 8px; margin-top: 8px;
        }

        /* 展开详情 */
        .card .detail { display: none; margin-top: 12px; }
        .card.expanded .detail { display: block; }
        .card .detail .risk {
            background: rgba(239,68,68,.08);
            border-left: 3px solid #ef4444;
            padding: 10px 14px;
            border-radius: 0 8px 8px 0;
            color: #fca5a5;
            font-size: 0.88em;
            line-height: 1.7;
        }
        .card .expand-hint { color: #475569; font-size: 0.8em; text-align: right; margin-top: 6px; }

        /* 无结果 */
        .no-result {
            text-align: center; padding: 60px 20px;
            color: #64748b; font-size: 1.1em;
            display: none;
        }

        /* 回到顶部 */
        #backTop {
            position: fixed; bottom: 30px; right: 30px;
            width: 46px; height: 46px;
            background: #38bdf8; color: #0f172a;
            border: none; border-radius: 50%;
            font-size: 1.3em; cursor: pointer;
            display: none; z-index: 99;
            box-shadow: 0 4px 15px rgba(56,189,248,.3);
        }

        @media (max-width: 500px) {
            .cards { grid-template-columns: 1fr; }
            .header h1 { font-size: 1.5em; }
        }
    </style>
</head>
<body>
<div class="app">
    <div class="header">
        <h1>⚡ 法律期限速查系统</h1>
        <p>涵盖民法 · 民事诉讼 · 刑事诉讼 · 行政法 · 劳动法 · 商法 · 经济法 关键期限 | 点击卡片查看详情</p>
    </div>

    <div class="search-area">
        <input type="text" id="searchInput" placeholder="输入关键词搜索：如 撤销、工伤、仲裁、15日、3年...">
    </div>

    <div class="filters" id="catFilters">
        <button class="fbtn active" data-cat="all">全部</button>
        <button class="fbtn" data-cat="civil">民事实体</button>
        <button class="fbtn" data-cat="procedure">民事诉讼</button>
        <button class="fbtn" data-cat="criminal">刑事诉讼</button>
        <button class="fbtn" data-cat="admin">行政法</button>
        <button class="fbtn" data-cat="labor">劳动法</button>
        <button class="fbtn" data-cat="commercial">商法</button>
        <button class="fbtn" data-cat="economic">经济法</button>
        <button class="fbtn warn-btn" data-cat="warning">⚠ 高风险</button>
    </div>

    <div class="duration-filters" id="durFilters">
        <span style="color:#64748b;font-size:.85em;line-height:2">按期限长度：</span>
        <button class="dbtn active" data-dur="all">全部</button>
        <button class="dbtn" data-dur="short">≤15日</button>
        <button class="dbtn" data-dur="medium">1-6个月</button>
        <button class="dbtn" data-dur="long">1-3年</button>
        <button class="dbtn" data-dur="vlong">3年以上</button>
    </div>

    <div class="stats" id="stats"></div>
    <div class="cards" id="cardList"></div>
    <div class="no-result" id="noResult">😔 没有找到匹配的期限条目，试试其他关键词？</div>
</div>
<button id="backTop" onclick="window.scrollTo({top:0,behavior:'smooth'})">↑</button>

<script>
const DATA = [
    // 劳动法
    { name:"劳动争议仲裁时效", cat:"labor", warn:true, dur:"long",
      time:"1年", desc:"自当事人知道或应当知道其权利被侵害之日起1年内提出仲裁申请。劳动关系存续期间因拖欠劳动报酬发生争议的，不受此限，但应在劳动关系终止之日起1年内提出。",
