      law:"《民事诉讼法》第221条" },
    { name:"仲裁裁决撤销申请", cat:"procedure", warn:true, dur:"medium",
      time:"6个月", desc:"当事人提出证据证明裁决有法定撤销情形的，可自收到裁决书之日起6个月内向仲裁委所在地中级法院申请撤销。",
      risk:"逾期未申请，撤销权消灭。",
      law:"《仲裁法》第59条" },
    { name:"公示催告申报权利期", cat:"procedure", warn:false, dur:"medium",
      time:"不少于60日", desc:"法院决定受理公示催告申请后，应同时通知支付人止付，并在3日内发出公告，催促利害关系人申报权利。公示催告期间由法院定，但不得少于60日。",
      risk:"利害关系人应在公示催告期间申报权利。无人申报的，法院根据申请作出除权判决，宣告票据无效。",
      law:"《民事诉讼法》第225条" },
];

const CAT_NAMES = { labor:"劳动法", commercial:"商法", economic:"经济法", civil:"民事实体", procedure:"诉讼程序" };
const DUR_NAMES = { short:"≤15日", medium:"1-6个月", long:"1-3年", vlong:"3年以上" };

let curCat = "all", curDur = "all", curSearch = "";

function render() {
    const filtered = DATA.filter(d => {
        if (curCat === "warning") { if (!d.warn) return false; }
        else if (curCat !== "all" && d.cat !== curCat) return false;
        if (curDur !== "all" && d.dur !== curDur) return false;
        if (curSearch) {
            const s = curSearch.toLowerCase();
            const t = (d.name + d.time + d.desc + d.risk + d.law).toLowerCase();
            if (!t.includes(s)) return false;
        }
        return true;
    });

    // 统计
    const total = filtered.length;
    const warnCount = filtered.filter(d => d.warn).length;
    const catCount = new Set(filtered.map(d => d.cat)).size;
    document.getElementById('stats').innerHTML = `
        <div class="stat-card"><div class="num">${total}</div><div class="label">匹配条目</div></div>
        <div class="stat-card warn"><div class="num">${warnCount}</div><div class="label">高风险项</div></div>
        <div class="stat-card"><div class="num">${catCount}</div><div class="label">涉及门类</div></div>
    `;

    // 卡片
    const list = document.getElementById('cardList');
    const noRes = document.getElementById('noResult');
    if (!filtered.length) { list.innerHTML = ''; noRes.style.display = 'block'; return; }
    noRes.style.display = 'none';

    list.innerHTML = filtered.map((d, i) => `
        <div class="card cat-${d.cat} ${d.warn ? 'warn-card' : ''}" onclick="this.classList.toggle('expanded')">
            ${d.warn ? '<div class="warn-badge">⚠ 高风险</div>' : ''}
            <div class="cat-tag">${CAT_NAMES[d.cat]}</div>
            <div class="title">${highlight(d.name)}</div>
            <div class="duration">${highlight(d.time)}</div>
            <div class="desc">${highlight(truncate(d.desc, 80))}</div>
            <div class="detail">
                <div class="desc" style="margin-bottom:10px">${highlight(d.desc)}</div>
                <div class="risk">${highlight(d.risk)}</div>
                <div class="law-ref">📖 ${highlight(d.law)}</div>
            </div>
