function truncate(s, n) { return s.length > n ? s.slice(0, n) + '...' : s; }

function highlight(text) {
    if (!curSearch) return text;
    const re = new RegExp('(' + curSearch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
    return text.replace(re, '<mark style="background:#fbbf24;color:#0f172a;border-radius:2px;padding:0 2px">$1</mark>');
}

