* { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: 'Microsoft YaHei', sans-serif;
  background: #0f172a;
  color: #e2e8f0;
  min-height: 100vh;
}
.app { max-width: 1400px; margin: 0 auto; padding: 20px; }
.header {
  text-align: center; padding: 30px 20px 20px;
  background: linear-gradient(135deg, #1e293b, #334155);
  border-radius: 16px; margin-bottom: 20px; border: 1px solid #475569;
}
.header h1 { font-size: 2em; color: #38bdf8; margin-bottom: 6px; }
.header p { color: #94a3b8; font-size: 0.95em; }
.search-area { display: flex; gap: 12px; margin: 20px 0; flex-wrap: wrap; align-items: center; }
.search-input {
  flex: 1; min-width: 250px; padding: 14px 20px;
  background: #1e293b; border: 2px solid #475569; border-radius: 12px;
  color: #f1f5f9; font-size: 1.05em; transition: border-color .3s;
}
.search-input:focus { outline: none; border-color: #38bdf8; }
.search-input::placeholder { color: #64748b; }
.filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
.fbtn {
  padding: 8px 18px; background: #1e293b; color: #94a3b8;
  border: 1px solid #475569; border-radius: 20px; cursor: pointer;
  font-size: 0.9em; transition: all .2s;
}
.fbtn:hover { border-color: #38bdf8; color: #38bdf8; }
.fbtn.active { background: #38bdf8; color: #0f172a; border-color: #38bdf8; font-weight: 600; }
.fbtn.warn-btn.active { background: #ef4444; border-color: #ef4444; color: #fff; }
.stats { display: flex; gap: 12px; margin-bottom: 20px; flex-wrap: wrap; }
.stat-card {
  flex: 1; min-width: 140px; background: #1e293b;
  border: 1px solid #475569; border-radius: 12px; padding: 16px; text-align: center;
}
.stat-card .num { font-size: 2em; font-weight: 700; color: #38bdf8; }
.stat-card .label { font-size: 0.85em; color: #94a3b8; margin-top: 4px; }
.stat-card.warn .num { color: #ef4444; }
.duration-filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
.dbtn {
  padding: 6px 14px; background: transparent; color: #94a3b8;
  border: 1px dashed #475569; border-radius: 16px; cursor: pointer;
  font-size: 0.85em; transition: all .2s;
}
.dbtn:hover { border-color: #a78bfa; color: #a78bfa; }
.dbtn.active { background: #a78bfa; color: #0f172a; border-style: solid; border-color: #a78bfa; font-weight: 600; }
.cards { display: grid; grid-template-columns: repeat(auto-fill, minmax(420px, 1fr)); gap: 16px; }
.card {
  background: #1e293b; border: 1px solid #334155; border-radius: 14px;
  padding: 20px; transition: all .3s; cursor: pointer; position: relative; overflow: hidden;
}
.card:hover { border-color: #38bdf8; transform: translateY(-2px); box-shadow: 0 8px 25px rgba(56,189,248,.1); }
.card.warn-card { border-left: 4px solid #ef4444; }
.cat-tag {
  display: inline-block; padding: 3px 10px; border-radius: 10px;
  font-size: 0.75em; font-weight: 600; margin-bottom: 10px;
}
.cat-labor .cat-tag { background: #164e63; color: #22d3ee; }
.cat-commercial .cat-tag { background: #1e3a5f; color: #60a5fa; }
.cat-economic .cat-tag { background: #365314; color: #a3e635; }
.cat-civil .cat-tag { background: #4a1d96; color: #c4b5fd; }
.cat-procedure .cat-tag { background: #78350f; color: #fbbf24; }
.card .title { font-size: 1.15em; font-weight: 700; color: #f1f5f9; margin-bottom: 8px; }
.card .duration {
  display: inline-block; padding: 4px 12px; background: rgba(56,189,248,.15);
  color: #38bdf8; border-radius: 8px; font-weight: 700; font-size: 1.05em; margin-bottom: 10px;
}
.card.warn-card .duration { background: rgba(239,68,68,.15); color: #ef4444; }
.warn-badge {
  position: absolute; top: 12px; right: 12px;
  background: #ef4444; color: #fff; padding: 2px 8px;
  border-radius: 6px; font-size: 0.7em; font-weight: 700;
}
.card .desc { color: #94a3b8; font-size: 0.9em; line-height: 1.7; margin-bottom: 8px; }
.card .law-ref {
  font-size: 0.8em; color: #64748b;
  border-top: 1px solid #334155; padding-top: 8px; margin-top: 8px;
}
.detail { margin-top: 12px; }
.detail .risk {
  background: rgba(239,68,68,.08); border-left: 3px solid #ef4444;
  padding: 10px 14px; border-radius: 0 8px 8px 0;
  color: #fca5a5; font-size: 0.88em; line-height: 1.7;
}
.expand-hint { color: #475569; font-size: 0.8em; text-align: right; margin-top: 6px; }
.no-result { text-align: center; padding: 60px 20px; color: #64748b; font-size: 1.1em; }
#backTop {
  position: fixed; bottom: 30px; right: 30px; width: 46px; height: 46px;
  background: #38bdf8; color: #0f172a; border: none; border-radius: 50%;
  font-size: 1.3em; cursor: pointer; z-index: 99;
  box-shadow: 0 4px 15px rgba(56,189,248,.3);
}
mark { background: #fbbf24; color: #0f172a; border-radius: 2px; padding: 0 2px; }
@media (max-width: 500px) {
  .cards { grid-template-columns: 1fr; }
  .header h1 { font-size: 1.5em; }
}

